// Extension 2: n8n-First Prototype
// This Code node computes the streak/coins reward logic that was later
// migrated to Express (recalculateStudentState in apps/server/src/index.ts).
//
// WHY WE PROTOTYPED HERE:
// n8n's visual workflow made it easy to iterate on the reward rule quickly
// without restarting the Express server. We could change the formula, test
// it against live webhook payloads, and see results instantly in the n8n UI.
//
// WHY WE MIGRATED TO EXPRESS:
// 1. Accuracy: Correct streak calculation needs access to the full session
//    history (all past dates). n8n receives only the current session payload,
//    not the full history. Express queries db.json for all sessions.
// 2. Type safety: Express + TypeScript catches formula errors at compile time.
//    n8n Code nodes have no type checking.
// 3. Testability: We can write unit tests for recalculateStudentState().
//    n8n workflow nodes are hard to unit-test without running n8n.
// 4. Atomicity: Express computes rewards INSIDE the same db write transaction
//    as the action replay. In n8n, reward computation would be decoupled,
//    risking a crash between sync and notification causing lost rewards.

const session = $json.session;
const incomingStreak = $json.streak; // pre-computed by Express, used as fallback
const incomingCoins = $json.totalCoins;

// Simplified reward rule (prototype quality - accurate version lives in Express)
// Coins = targetDuration minutes (1 coin per minute of focused study)
const coinsEarned = session.targetDuration;

// Streak: in this prototype we trust the pre-computed streak from Express.
// A full n8n implementation would need a sub-workflow to query session history.
const streak = incomingStreak;

const message = `🌟 Focus session complete! +${coinsEarned} coins earned.\nStreak: ${streak} day${streak !== 1 ? 's' : ''}. Keep it up!`;

return {
  json: {
    studentId: $json.studentId,
    session: session,
    coinsAwarded: coinsEarned,
    totalCoins: incomingCoins,
    streak: streak,
    message: message,
    computedBy: 'n8n-prototype'
  }
};
